---
interface Props {
  title: string;
  speaker?: string;
  date?: string;
  series?: string;
  scripture?: string;
  href: string;
}

const { title, speaker, date, series, scripture, href } = Astro.props;

const formattedDate = date
  ? new Date(date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })
  : undefined;
---

<a class="sermon-card" href={href} data-series={series ?? ''}>
  <div class="sermon-card__body">
    {series && <span class="sermon-card__badge">{series}</span>}
    <h3 class="sermon-card__title">{title}</h3>
    <div class="sermon-card__meta">
      {formattedDate && <span class="sermon-card__date">{formattedDate}</span>}
      {speaker && <span class="sermon-card__speaker">{speaker}</span>}
    </div>
    {scripture && <p class="sermon-card__scripture">{scripture}</p>}
  </div>
</a>

<style>
  .sermon-card {
    display: flex;
    flex-direction: column;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    overflow: hidden;
    text-decoration: none;
    color: inherit;
    transition: box-shadow var(--transition), transform var(--transition);
  }

  .sermon-card:hover {
    box-shadow: 0 4px 16px rgba(26, 26, 46, 0.1);
    transform: translateY(-2px);
  }

  .sermon-card:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .sermon-card__body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .sermon-card__badge {
    display: inline-block;
    align-self: flex-start;
    font-family: var(--font-body);
    font-size: var(--text-xs);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--color-terracotta);
    background-color: color-mix(in srgb, var(--color-terracotta) 10%, transparent);
    padding: var(--space-1) var(--space-3);
    border-radius: var(--radius-sm);
  }

  .sermon-card__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .sermon-card__meta {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-2);
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
  }

  .sermon-card__meta > span + span::before {
    content: '·';
